{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires reconstructing a sequence of operations based on tree structures. This involves identifying the structural differences (the merges) and then determining a valid topological order for those operations.",
  "helpers": [
    {
      "label": "structural_diff_analyzer",
      "instructions": "Compare the initial tree and the final tree to identify the specific set of 'merge' operations performed. A merge operation combines two sibling nodes into one. Identify which pairs of nodes were merged and which nodes were removed/replaced to reach the final state."
    },
    {
      "label": "topological_order_generator",
      "instructions": "Given the set of identified merge operations, determine a valid execution sequence. A merge can only occur if the parent of the siblings involved has not been modified by a subsequent merge that changes the sibling structure in a way that invalidates the current operation. Ensure the sequence respects the bottom-up or top-down constraints inherent in tree transformations."
    }
  ],
  "synthesis_brief": "Combine the list of identified merge operations from the structural analyzer with the valid execution sequence from the topological generator to produce the final reconstructed sequence of operations."
}
```

